-- Fix: Create reliability category
INSERT INTO doc_template_category (category_code, category_name, parent_id, gjb_reference, description, order_num, status)
SELECT 'REL_SPEC', E'\u53ef\u9760\u6027\u8bbe\u8ba1\u6587\u4ef6', 0, 'GJB 450B-2021', E'\u53ef\u9760\u6027\u8bbe\u8ba1\u76f8\u5173\u7684\u6587\u6863\u6a21\u677f', 16, 'ACTIVE'
WHERE NOT EXISTS (SELECT 1 FROM doc_template_category WHERE category_code = 'REL_SPEC');

-- Fix: Update doc_template_v2 rows to have valid category_id
UPDATE doc_template_v2 
SET category_id = (SELECT id FROM doc_template_category WHERE category_code = 'REL_SPEC')
WHERE template_code IN ('TPL-REL-OUTLINE', 'TPL-REL-DERATING', 'TPL-REL-PRED', 'TPL-REL-ALLOC')
  AND category_id IS NULL;

